import { FiMessageSquare } from 'react-icons/fi';
const ChatPage = () => (
  <div className="flex flex-col gap-6">
    <h1 className="text-2xl font-bold text-gray-900">Chat</h1>
    <div className="card flex flex-col items-center justify-center py-24 gap-4 text-gray-400">
      <FiMessageSquare size={48} />
      <p className="text-lg font-medium">Chat temps réel</p>
      <p className="text-sm">Connectez Socket.io au collab-service (port 3004)</p>
    </div>
  </div>
);
export default ChatPage;
